104	error_t partial_decryption_t::check_partial_decryption_helper(const ecc_point_t& Qi, const ciphertext_t& ciphertext,
105	                                                              ecurve_t curve) const {
106	  error_t rv = UNINITIALIZED_ERROR;
107	
108	  if (rv = curve.check(Qi))
109	    return coinbase::error(rv, "partial_decryption_t::check_partial_decryption_helper: check Qi failed");
110	  if (rv = curve.check(Xi))
111	    return coinbase::error(rv, "partial_decryption_t::check_partial_decryption_helper: check Xi failed");
112	
113	  const auto& G = curve.generator();
114	  const mod_t& q = curve.order();
115	  if (!q.is_in_range(ei) || !q.is_in_range(fi)) return coinbase::error(E_CRYPTO);
116	
117	  const ecc_point_t& R1 = ciphertext.R1;
118	  ecc_point_t Yi = fi * R1 - ei * Xi;
119	  ecc_point_t Zi = fi * G - ei * Qi;
120	
121	  bn_t ei_test = ro::hash_number(Xi, Yi, Zi).mod(q);
122	  if (ei != ei_test) return coinbase::error(E_CRYPTO);
123	
124	  return SUCCESS;
125	}
