127	error_t combine_additive(const public_key_t& pub_key, const pub_shares_t& Qi, mem_t label,
128	                         const partial_decryptions_t& partial_decryptions, const ciphertext_t& ciphertext,
129	                         buf_t& plain) {
130	  error_t rv = UNINITIALIZED_ERROR;
131	  const auto& curve = pub_key.Q.get_curve();
132	  int n = int(Qi.size());
133	  for (const auto& _Qi : Qi) {
134	    if (rv = curve.check(_Qi)) return coinbase::error(rv, "combine_additive: check Qi failed");
135	  }
136	  if ((int)partial_decryptions.size() != n) return coinbase::error(E_CRYPTO);
137	
138	  if (rv = ciphertext.verify(pub_key, label)) return rv;
139	
140	  ecc_point_t V = curve.infinity();
141	  for (int i = 0; i < n; i++) {
142	    const partial_decryption_t& partial_decryption = partial_decryptions[i];
143	
144	    const int rid = partial_decryption.rid;
145	    if (rid < 1 || rid > n) return coinbase::error(E_CRYPTO);
146	    if (rv = partial_decryption.check_partial_decryption_helper(Qi[rid - 1], ciphertext, curve)) return rv;
147	
148	    V += partial_decryption.Xi;
149	  }
150	
151	  if (rv = ciphertext.decrypt(V, plain, label)) return rv;
152	  return SUCCESS;
153	}
