155	error_t combine(const ss::ac_t& ac, const public_key_t& pub_key, ss::ac_pub_shares_t& pub_shares, mem_t label,
156	                const ss::party_map_t<partial_decryption_t> partial_decryptions, const ciphertext_t& ciphertext,
157	                buf_t& plain) {
158	  error_t rv = UNINITIALIZED_ERROR;
159	
160	  if (!ac.enough_for_quorum(partial_decryptions)) return coinbase::error(E_CRYPTO);
161	
162	  if (rv = ciphertext.verify(pub_key, label)) return rv;
163	
164	  ss::ac_pub_shares_t Vs;
165	  for (const auto& [name, partial_decryption] : partial_decryptions) {
166	    if (rv = partial_decryption.check_partial_decryption_helper(pub_shares[name], ciphertext, pub_key.Q.get_curve()))
167	      return rv;
168	    if (rv = pub_key.Q.get_curve().check(partial_decryption.Xi)) return rv;
169	
170	    Vs[name] = partial_decryption.Xi;
171	  }
172	
173	  ecc_point_t V;
174	  if (rv = ac.reconstruct_exponent(Vs, V)) return rv;
175	
176	  if (rv = ciphertext.decrypt(V, plain, label)) return rv;
177	  return SUCCESS;
178	}
