25	static error_t validate_public_key(const coinbase::crypto::tdh2::public_key_t& pk) {
26	  if (!pk.Q.valid() || !pk.Gamma.valid()) return coinbase::error(E_FORMAT, "invalid public key");
27	  const auto curve = pk.Q.get_curve();
28	  if (!curve.valid()) return coinbase::error(E_FORMAT, "invalid public key");
29	  if (pk.Gamma.get_curve() != curve) return coinbase::error(E_FORMAT, "invalid public key");
30	
31	  // Enforce subgroup / infinity checks (DoS resistance and misuse-hardening).
32	  if (curve.check(pk.Q)) return coinbase::error(E_FORMAT, "invalid public key");
33	  if (curve.check(pk.Gamma)) return coinbase::error(E_FORMAT, "invalid public key");
34	
35	  // `Gamma` is deterministically derived from `(Q, sid)` and must match.
36	  const auto expected_gamma = coinbase::crypto::ro::hash_curve(mem_t("TDH2-Gamma"), pk.Q, pk.sid).curve(curve);
37	  if (pk.Gamma != expected_gamma) return coinbase::error(E_FORMAT, "invalid public key");
38	  return SUCCESS;
39	}
