41	struct private_share_blob_v1_t {
42	  uint32_t version = private_share_blob_version_v1;
43	  uint32_t curve = 0;  // coinbase::api::curve_id
44	
45	  // Role/index id: 1..n, aligned with `job.party_names` order.
46	  int rid = 0;
47	  coinbase::crypto::bn_t x;
48	  coinbase::crypto::tdh2::public_key_t pub_key;
49	
50	  void convert(coinbase::converter_t& c) { c.convert(version, curve, rid, x, pub_key); }
51	};
