76	static error_t serialize_public_outputs(const coinbase::api::job_mp_t& job,
77	                                        const coinbase::mpc::eckey::key_share_mp_t& key, const buf_t& sid,
78	                                        buf_t& public_key, std::vector<buf_t>& public_shares) {
79	  const coinbase::crypto::tdh2::public_key_t pk(key.Q, sid);
80	  public_key = pk.to_bin();
81	
82	  public_shares.clear();
83	  public_shares.reserve(job.party_names.size());
84	  for (const auto& name_view : job.party_names) {
85	    const std::string name(name_view);
86	    const auto it = key.Qis.find(name);
87	    if (it == key.Qis.end()) return coinbase::error(E_FORMAT, "DKG output missing public share");
88	    public_shares.emplace_back(it->second.to_compressed_bin());
89	  }
90	  return SUCCESS;
91	}
