93	static error_t serialize_private_share(curve_id curve, coinbase::api::party_idx_t self,
94	                                       const coinbase::crypto::bn_t& x_share,
95	                                       const coinbase::crypto::tdh2::public_key_t& pk, buf_t& private_share) {
96	  private_share_blob_v1_t blob;
97	  blob.curve = static_cast<uint32_t>(curve);
98	  blob.rid = static_cast<int>(self) + 1;  // 1..n (aligned with job.party_names order)
99	  blob.x = x_share;
100	  blob.pub_key = pk;
101	  private_share = coinbase::convert(blob);
102	  return SUCCESS;
103	}
