176	error_t encrypt(mem_t public_key, mem_t plaintext, mem_t label, buf_t& ciphertext) {
177	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(public_key, "public_key",
178	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
