291	                   const std::vector<mem_t>& partial_decryptions, mem_t ciphertext, buf_t& plaintext) {
292	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(public_key, "public_key",
293	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
294	    return rv;
295	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
296	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
297	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
298	    return rv;
299	  if (const error_t rv = coinbase::api::detail::validate_mem_vec_arg_max_size(
300	          public_shares, "public_shares", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
301	    return rv;
302	  if (const error_t rv = coinbase::api::detail::validate_mem_vec_arg_max_size(
303	          partial_decryptions, "partial_decryptions", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
304	    return rv;
305	
306	  if (party_names.size() != public_shares.size())
307	    return coinbase::error(E_BADARG, "party_names and public_shares size mismatch");
308	  if (partial_decryption_party_names.size() != partial_decryptions.size())
309	    return coinbase::error(E_BADARG, "partial_decryption_party_names and partial_decryptions size mismatch");
310	
311	  coinbase::crypto::tdh2::public_key_t pk;
312	  error_t rv = pk.from_bin(public_key);
313	  if (rv) return rv;
314	  if (rv = validate_public_key(pk)) return rv;
315	
316	  const auto curve = pk.Q.get_curve();
317	  if (!curve.valid()) return coinbase::error(E_FORMAT, "public key missing curve");
318	
319	  // Convert access structure to internal representation and validate that leaf names match `party_names`.
320	  coinbase::crypto::ss::ac_owned_t ac;
321	  rv = coinbase::api::detail::to_internal_access_structure(access_structure, party_names, curve, ac);
