331	  for (size_t i = 0; i < party_names.size(); i++) {
332	    const auto name_view = party_names[i];
333	    if (name_view.empty()) return coinbase::error(E_BADARG, "party name must be non-empty");
334	    if (!seen_party_names.insert(name_view).second) return coinbase::error(E_BADARG, "duplicate party name");
335	    coinbase::crypto::ecc_point_t Qi;
336	    rv = Qi.from_bin(curve, public_shares[i]);
337	    if (rv) return rv;
338	    pub_shares_map.emplace(std::string(name_view), std::move(Qi));
339	  }
340	
341	  coinbase::crypto::ss::party_map_t<coinbase::crypto::tdh2::partial_decryption_t> partials_map;
342	  partials_map.clear();
343	  std::set<std::string_view> seen_partial_names;
344	  for (size_t i = 0; i < partial_decryptions.size(); i++) {
345	    const auto name_view = partial_decryption_party_names[i];
346	    if (name_view.empty()) return coinbase::error(E_BADARG, "partial decryption party name must be non-empty");
347	    if (!seen_partial_names.insert(name_view).second)
348	      return coinbase::error(E_BADARG, "duplicate partial decryption party name");
349	
350	    const std::string name(name_view);
351	    if (pub_shares_map.find(name) == pub_shares_map.end())
