353	
354	    coinbase::crypto::tdh2::partial_decryption_t partial;
355	    rv = coinbase::convert(partial, partial_decryptions[i]);
356	    if (rv) return rv;
357	    partials_map[name] = std::move(partial);
358	  }
359	
360	  return coinbase::crypto::tdh2::combine(ac, pk, pub_shares_map, label, partials_map, ct, plaintext);
